                    <p className="text-ch-text-muted">
                        Configure as informações da sua empresa
                    </p>
                </div>
                {!hasChanges ? (
                    <Button onClick={handleEdit} variant="outline" className="border-ch-dark-gray">
                        Editar
                    </Button>
                ) : (
                    <div className="flex gap-2">
                        <Button onClick={handleCancel} variant="outline" className="border-ch-dark-gray">
                            Cancelar
                        </Button>
                        <Button
                            onClick={handleSave}
                            disabled={updateCompany.isPending}
                            className="bg-ch-orange hover:bg-ch-orange/90"
                        >
                            {updateCompany.isPending ? (
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            ) : (
                                <Save className="w-4 h-4 mr-2" />
                            )}
                            Salvar
                        </Button>
                    </div>
